@Service
public class JobTaskMethodScheduling {

    @Autowired
    private AsyncUploadServiceImpl uploadService;

    private final Map<CrowdPackSyncTargetEnum, Supplier<String>> FUNCTION_MAP = new HashMap<>();

    @PostConstruct
    public void init() {
        FUNCTION_MAP.put(CrowdPackSyncTargetEnum.JD, uploadService::syncCrowdPack2JD);
    }

